import React, { useState } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Upload, User, Briefcase } from 'lucide-react';

export default function ResumeXAI(){
 const [page,setPage]=useState('login');
 return (
 <div className='min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-950 text-white p-6'>
  <div className='max-w-5xl mx-auto'>
   <h1 className='text-4xl font-bold mb-6'>ResumeX AI</h1>
   {page==='login' && (
    <Card className='rounded-2xl bg-white/10 backdrop-blur p-6'>
      <CardContent className='space-y-4'>
        <Input placeholder='Username'/>
        <Input placeholder='Password' type='password'/>
        <Button className='w-full' onClick={()=>setPage('dashboard')}>Login</Button>
      </CardContent>
    </Card>
   )}
   {page==='dashboard' && (
    <div className='grid md:grid-cols-3 gap-4'>
      <Card className='bg-white/10 p-4 rounded-2xl'><CardContent><User className='mb-2'/>Candidates<br/>124</CardContent></Card>
      <Card className='bg-white/10 p-4 rounded-2xl'><CardContent><Briefcase className='mb-2'/>Jobs<br/>18</CardContent></Card>
      <Card className='bg-white/10 p-4 rounded-2xl'><CardContent><Upload className='mb-2'/>Uploads<br/>342</CardContent></Card>
      <Card className='md:col-span-3 bg-white/10 p-6 rounded-2xl'>
        <CardContent className='space-y-3'>
          <h2 className='text-2xl font-semibold'>Upload Resume</h2>
          <Input type='file'/>
          <Button>Upload</Button>
        </CardContent>
      </Card>
    </div>
   )}
  </div>
 </div>
 )
}
